/* 复选框样式 */
input[type='checkbox'] {
  background:#ffffff center/cover; 
  border: 2px solid #ffffff; 
  border-radius: 3px;
  box-shadow: 
    inset 3px 3px 2px rgba(148, 159, 117, 0.6), 
    3px 4px 0px rgba(148, 159, 117, 0.2); 
  width: 19px; /* 宽度 */
  height: 19px; /* 高度 */
}

/* 悬停*/
input[type='checkbox']:hover {
background:#ffffff center/cover; 
  box-shadow: 
    inset -2px -2px 2px rgba(148, 159, 117, 0.8),
    4px 4px 6px rgba(148, 159, 117, 0.5);
}

/* 选中 */
input[type='checkbox']:checked {
  background:rgba(0,0,0,0) center/cover; 
  border: 0px solid #393939; 
  box-shadow: 
    inset 2px 3px 4px rgba(0,0,0,0),
    2px 2px 5px rgba(0,0,0,0);
}

/* 选中图标 */
input[type='checkbox'] {
  position: relative; /* 确保伪元素相对于复选框定位 */
  -webkit-appearance: none; /* 清除浏览器默认样式 */
  appearance: none;
}

input[type='checkbox']:checked::after {
  content: '';
  position: absolute;
  width: 30px;
  height: 30px;
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); 
  background-size: contain;
  background-repeat: no-repeat;
  z-index: 2;
  pointer-events: none;
  top: -5px;
  right: -7px;
  filter: none !important; /* 防止过滤器影响图像 */
  mix-blend-mode: normal !important; /* 禁用混合模式 */
  opacity: 1 !important; /* 确保完全不透明 */
}
input[type='checkbox']:checked {
  position: relative;
  overflow: visible !important;
}
/* 👁不可删👁勾选隐藏 */
input[type="checkbox"]::before {
  content: none !important;
}



