    inset 2px 2px 4px rgba(0,0,0, 0),
    6px 6px 10px rgba(156, 169, 111, 0.5); /* 悬停阴影加深 */
}

.drawer-content select:focus {
  box-shadow: 
    inset 0px 2px 1px rgba(156, 169, 111, 0.1),
    0 0 0 2px rgba(0,0,0, 0), 
    6px 6px 10px rgba(156, 169, 111, 0.25); /* 聚焦增强效果 */
transform: translateY(-6px);
}

/* ===== 输入框 ===== */
input:not([type="file" i], [type="image" i], [type="checkbox" i], [type="radio" i]) {
background: rgba(255, 255, 255, 0.6);
  border: 2px solid #ffffff;
border-radius: 0px 0px 10px 10px;
  box-shadow: 
    inset 0px 3px 0px rgba(156, 169, 111, 0.15),
    4px 4px 1px rgba(156, 169, 111, 0.2);
  color: #969696;
  padding: 10px 14px;
  height: 8px;
  font-size: 10px;
  transition: all 0.25s ease;
}



/* ===== 文本框 ===== */
.text_pole {
background: rgba(255, 255, 255, 0.7);
  border: 2px solid #ffffff;
border-radius: 0px 0px 10px 10px;
  box-shadow: 
    inset 2px 2px 3px rgba(156, 169, 111, 0.3),
    2px 2px 3px rgba(156, 169, 111, 0.6);
  color: #969696;
  padding: 5px;
  transition: all 0.3s ease;
}

.text_pole:focus {
  box-shadow: 
    inset 2px 2px 4px rgba(156, 169, 111, 0.2),
    0 0 0 0px rgba(156, 169, 111, 0),
    4px 4px 3px rgba(156, 169, 111, 0.3);
}

/* ===== 预设 ===== */
#completion_prompt_manager #completion_prompt_manager_list {
  background: rgba(255, 255, 255, 0.9);
  border: 2px solid #ffffff;
 border-radius: 0px 0px 10px 10px;
  box-shadow: 
    inset 1px 1px 2px rgba(156, 169, 111,0.2),
    4px 4px 5px rgba(156, 169, 111, 0.1);
  color: #737E68;
}

/* 滚动条 */
#completion_prompt_manager_list::-webkit-scrollbar-thumb {
  background: rgba(156, 169, 111, 0.1);
}

/* 基础 */
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt {
    align-items: center;
    padding: 0.5em;
    border: 0px solid #ffffff; 
background: rgba(255, 255, 255, 1)；
border-radius: 0px 0px 0px 0px; 
    box-shadow: 
        inset 0px -2px 0px rgba(156, 169, 111, 0.3),
        3px 3px 8px rgba(156, 169, 111, 0.2);
    margin-bottom: 14px;
    transition: all 0.2s ease; 
}

/* 禁用 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt.completion_prompt_manager_prompt_disabled {
background: #F2F4EC; /* 白色背景 */
    border: 2px solid #F2F4EC;
box-shadow: 
        inset 0px 2px 3px rgba(156, 169, 111, 0.2),
        3px 3px 8px rgba(0,0,0, 0);
}

/* 悬停 */
#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt:hover {
box-shadow: 
        inset -2px 2px 0px rgba(156, 169, 111, 0.2),
        3px 3px 8px rgba(156, 169, 111, 0.2);
transform: translateY(-8px);
}

#completion_prompt_manager #completion_prompt_manager_list li.completion_prompt_manager_prompt span span span {
    filter: none; /* 移除开关阴影 */
}
