🦋ui区美化结束🍃弹窗齿轮美化开始============================================== */

/*————弹窗————*/
/*@hr*/
#toast-container > .toast {
    background-image: none !important;
    background-color: rgba(255, 255, 255, 0.85) !important;/* 背景颜色 */
    border: 3px solid rgba(255, 255, 255, 0.6);
    border-radius: 10px ;
    box-shadow: 0 2px 5px rgba(164, 178, 122, 0.3); /*阴影效果 */
    opacity: 0.95 !important;    /* 设置透明度 */
    padding: 10px 15px 10px 50px; /* 调整内边距，上-右-下-左 */
    min-height: 30px;/* 通知框最小高度 */ 
    max-width: 250px;/* 通知框最大宽度 */

}
.toast::before {
    content: '';
    position: absolute;
    left: 4px;/* 设置图标距离左边的位置 */
    top: 50%;/* 垂直居中对齐 */
    transform: translateY(-50%);
    width: 40px;/* 宽度 */
    height: 40px;/* 高度 */
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
}

/* 成功 (Success) 通知的自定义图标 */
.toast-success::before {
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
}

/* 错误 (Error) 通知的自定义图标 */
.toast-error::before {
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
}

/* 信息 (Info) 通知的自定义图标 */
.toast-info::before {
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
}

/* 警告 (Warning) 通知的自定义图标 */
.toast-warning::before {
    background-image: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=");
}

/* 消息文字样式 */
.toast-title {
    color: rgba(51, 57, 35, 0.85);
    font-size: 13px;
}

.toast-message {
    color: rgba(51, 57, 35, 0.65) !important ;
    font-size: 12px !important ;
} 
/*————加载齿轮————*/

#load-spinner {
    background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center center;
    background-size: contain;

    animation: float 3s ease-in-out infinite; 
}

/* 动画 */
@keyframes float {
    0%, 100% {
        transform: translateY(0); /* 起始和结束位置 */
    }
    50% {
        transform: translateY(-25px); /* 向上浮动 */
    }
}

/* 隐藏原图标 */
#load-spinner::before,
#load-spinner::after {
    display: none;
}
